#include <cmath>

using namespace std;

bool is_prime(int n) {
    if (n <= 1) {
        return false;
    }
    if (n == 2) {
        return true;
    }
    if (n % 2 == 0) {
        return false;
    }
    int max_divisor = sqrt(n) + 1;
    for (int i = 3; i < max_divisor; i += 2) {
        if (n % i == 0) {
            return false;
