    long long sum_a = 0;
    long long sum_b = 0;
    for (size_t index = 0; index < nums.size(); ++index) {
        if (is_prime(index)) {
            sum_a += nums[index];
        } else {
            sum_b += nums[index];
        }
    }
    return abs(sum_a - sum_b);
}
